var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"옳지, 옳지. 배고팠구나?","JPN":"よしよし、お腹が空いているんだね？","ENG":"There, there. Who's a good kitty? You must've been hungry.","TWN":"乖，乖，你餓了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"많이 줄 수는 없지만, 그래도 천천히 먹어~ 누가 뺏어가진 않으니까.","JPN":"これだけしかあげられないけど、ゆっくり食べるんだよ～取り上げる人は誰もいないから。","ENG":"It's not much, but you don't need to rush! No one's going to take it away from you.","TWN":"我只能給你這些，慢慢吃～不會有人跟你搶的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"배급 받은 분유라도 물에 타서 가져올 걸 그랬나? 밍밍하긴 해도 없는 것보단 나을 텐데.","JPN":"配給された粉ミルクでも水に溶かして持ってくればよかったかな？　味は薄いけど、ないよりはマシだったかも。","ENG":"Maybe I should've mixed up water with the ration formula. Not the best, but better than nothing.","TWN":"早知道就把分到的奶粉泡水裡拿過來，雖然口味淡一些，但有總比沒有好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데…… 고양이한테 과자나 우유를 줘도 됐던가?","JPN":"っていうか……猫ってお菓子とか牛乳をあげてもいいんだっけ？","ENG":"But... is it okay to give cats snacks or milk?","TWN":"不過……小貓可以吃餅乾或牛奶嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이~ 뭐, 아무렴 어때. 너도 배고픈 것보단 뭐라도 먹는 게 낫지?","JPN":"まぁいいか～、あなたもお腹を空かせてるぐらいなら、何でもいいから食べれる方がマシだよね？","ENG":"Oh, whatever. You'd prefer to eat something rather than starve, right, kitty?","TWN":"哎呀～隨便啦，有得吃總比餓肚子好吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"역시 여기 계셨군요. 시영 씨.","JPN":"やっぱりここにいたんですね。","ENG":"Just as I thought. You're here, Shiyoung.","TWN":"你果然在這裡，時雨。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아차차~ 이를 어쩌나. 또 들켜버렸네요.","JPN":"あちゃ～参ったね。またバレちゃった。","ENG":"Oh boy. Well, you found me.","TWN":"哎呀呀～這可怎麼辦，又被你逮個正著。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥! 오늘은 얼렁뚱땅 넘어갈 생각하지 말아요, 시영 씨!","JPN":"フン！　今日は適当にあしらおうなんて思わないでくださいね、シノンさん！","ENG":"Hmph! You're not getting away that easy today, Shiyoung!","TWN":"哼！你今天可別想糊弄過去，時雨！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 칼로리 블록은 생존자들을 위해 군에서 배급하는 소중한 식량이라고요.","JPN":"そのカロリーブロックは生存者のために、軍が支給する大事な食料なんです。","ENG":"That snack bar is a precious provision that the military provides to the survivors.","TWN":"那個營養口糧是軍隊分配給倖存者的珍貴糧食。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사람이 먹을 식량도 부족한데 자꾸 그렇게 식량을 낭비하시면, 시영 씨의 몫을 줄일 수밖에 없다구요!","JPN":"人間ですら満足に食べられないというのに、そんなふうに食料を無駄遣いされてはシノンさんの分を減らすしかありませんよ！","ENG":"We don't even have enough for our people. If you keep wasting food like that, we'll have no choice but to give you less food!","TWN":"光是要給人吃就已經很吃緊，如果一直這麼浪費糧食，就只好減少你的分量！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이~ 소심도 하셔라.","JPN":"いやいや～ケチだなぁ。","ENG":"Jeez, so apprehensive.","TWN":"哎呀～真是小氣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자꾸 그렇게 깐깐하게 구니까, 카린 양이 다른 사람들한테 인기가 없는 거라고요.","JPN":"そんなにケチ臭いから、カリンさんはモテないんですよ。","ENG":"You won't get popular if you keep acting so fussy about things.","TWN":"卡琳你老是這麼計較，大家才不喜歡你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇지, 야옹아?","JPN":"ね？　猫ちゃん？","ENG":"Right, kitty?","TWN":"對吧，喵喵？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"히, 히익! 자, 잠깐! 고양이 들이밀지 마세요!","JPN":"ひ、ひいっ！　ちょ、ちょっと！　猫をこっちに押し付けないでください！","ENG":"E-eeek! S-stop! Get the cat away from me!","TWN":"嗚，嗚！走開！不要讓牠靠近我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 그렇지만 이렇게 귀여운 걸요? 한 번 쓰다듬어 볼래요, 카린 양?","JPN":"はい？　でもこんなにかわいいのに？　撫でてみません？　カリンさん？","ENG":"Huh? But it's so cute! You want to pet it, Karin?","TWN":"什麼？可是牠很可愛欸？你要不要摸一摸，卡琳？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그게 아니라 전…… 에, 에, 엣!!","JPN":"い、いや、そうじゃなくて、私……は、は、はっ！！","ENG":"N-no, I-I-I'm... A-aah-aaaah–","TWN":"不，不要，我……哈，哈，哈！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"에, 엣―――취!!","JPN":"は、はくしょーーん！！","ENG":"A-ah-choo!","TWN":"哈——啾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};